1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	};
15	
16	const itemBasePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
17	
18	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
19	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
20	
21	const policyBasePremium = (items: Item[]): number => {
22	  const componentCounts = new Map<string, number>();
23	  let mainTotal = 0;
24	  for (const item of items) {
25	    if (COMPONENT_TYPES.has(item.type)) {
26	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
27	    } else {
28	      mainTotal += itemBasePremium(item);
29	    }
30	  }
31	  let componentTotal = 0;
32	  for (const [type, count] of componentCounts) {
33	    if (count === 3) {
34	      componentTotal += BLOCK_OF_THREE_BASE_PREMIUM;
35	    } else {
36	      componentTotal += count * itemBasePremium({ type });
37	    }
38	  }
39	  return mainTotal + componentTotal;
40	};
41	
42	const quotePremium = (items: Item[]): number => {
43	  const basePremium = policyBasePremium(items);
44	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
45	  const premiumBeforeFee = Math.ceil(basePremium + firstInsurance);
46	  return premiumBeforeFee + PROCESSING_FEE;
47	};
48	
49	export const runScenario = (scenario: Scenario): unknown => {
50	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
51	  return { results };
52	};
